#include <openssl/evp.h>
#include <stdio.h>

int main() {
    unsigned char buffer[32];
    size_t len = sizeof(buffer);

    // Use the default library context
    OSSL_LIB_CTX *libctx = OSSL_LIB_CTX_get_default();

    // RAND_bytes_ex returns 1 on success, 0 or negative on failure
    if (RAND_bytes_ex(libctx, buffer, len) <= 0) {
        fprintf(stderr, "Error generating random bytes\n");
        return 1;
    }

    // buffer now contains cryptographically secure random bytes
    for (int i = 0; i < len; i++) {
        printf("%02x", buffer[i]);
    }
    printf("\n");

    return 0;
}
```

