In OpenSSL 3.0, the `HMAC_*` functions (like `HMAC_Init`) are deprecated in favor of the `EVP_MAC` API. This new API is designed to work with the OpenSSL provider architecture.

To compute an HMAC-SHA256, you must `fetch` the "HMAC" algorithm, initialize a context with `OSSL_PARAM` to specify the `key` and the `digest` (SHA256), and then perform the update/final steps.

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <openssl/evp.h>
#include <openssl/params.h>
#include <openssl/mac.h>

/**
 * Computes HMAC-SHA256 using the OpenSSL 3.0 EVP_MAC API.
 */
int compute_hmac_sha256(const unsigned char *key, size_t key_len,
                        const unsigned char *msg, size_t msg_len,
                        unsigned char *out, size_t *out_len) {
    EVP_MAC *mac = NULL;
    EVP_MAC_CTX *ctx = NULL;
    int ret = 0;

    // 1. Fetch the HMAC implementation
    mac = EVP_MAC_fetch(NULL, "HMAC", NULL);
    if (mac == NULL) {
        goto err;
    }

    // 2. Create a new MAC context
    ctx = EVP_MAC_CTX_new(mac);
    if (ctx == NULL) {
        goto err;
    }

    // 3. Set up parameters: the key and the digest algorithm
    // OSSL_PARAM is the modern way to pass configuration to providers
    OSSL_PARAM params[2];
    params[0] = OSSL_PARAM_construct1("key", key, key_len);
    params[1] = OSSL_PARAM_construct1("digest", "SHA256", 0);

    // 4. Initialize the MAC context with parameters
    if (EVP_MAC_init(ctx, params, 2) <= 0) {
        goto err;
    }

    // 5. Update with the message data
    if (EVP_MAC_update(ctx, msg, msg_len) <= 0) {
        goto err;
    }

    // 6. Finalize and get the result
    // out_len is an in/out parameter; we pass the buffer size
    size_t actual_len = *out_len;
    if (EVP_MAC_final(ctx, out, &actual_len, *out_len) <= 0) {
        goto err;
    }
    *out_len = actual_len;
    ret = 1;

err:
    if (ctx) EVP_MAC_CTX_free(ctx);
    if (mac) EVP_MAC_free(mac);
    return ret;
}

int main() {
    const unsigned char *key = (unsigned char *)"secret_key";
    size_t key_len = strlen((char *)key);
    const unsigned char *msg = (unsigned char *)"The quick brown fox jumps over the lazy dog";
    size_t msg_len = strlen((char *)msg);

    unsigned char out[EVP_MAX_MD_SIZE];
    size_t out_len = sizeof(out);

    if (compute_hmac_sha256(key, key_len, msg, msg_len, out, &out_len)) {
        printf("HMAC-SHA256: ");
        for (size_t i = 0; i < out_len; i++) {
            printf("%02x", out[i]);
        }
        printf("\n");
    } else {
        fprintf(stderr, "Error computing HMAC\n");
        return 1;
    }

    return 0;
}
```

### Key Changes in the Modern API:
1.  **`EVP_MAC_fetch`**: Instead of using hardcoded algorithms, you fetch the algorithm name from the current provider list.
2.  **`OSSL_PARAM`**: Instead of passing the digest via a function call like `HMAC_Init_ex`, you pass a parameter array containing the `key` and the `digest` name (e.g., `"SHA256"`).
3.  **`EVP_MAC_CTX_new`**: Contexts are now created via the specific `EVP_MAC` factory rather than the legacy `HMAC_CTX_new`.
4.  **Decoupling**: The algorithm (HMAC) is decoupled from the underlying hash function (SHA256) via the `OSSL_PARAM` interface.

The supported extension mechanism in OpenSSL 3.0 is the **Provider** API (`OSSL_PROVIDER`). 

While the older "Engine" API is deprecated, Providers are the intended way to implement new algorithms or interface with hardware accelerators by providing a dispatch table of function pointers (implementations) for specific algorithm names.

### Loading a Custom Provider
To use your custom hardware provider, you must load it using `OSSL_PROVIDER_load`.

```c
#include <openssl/provider.h>
#include <openssl/err.h>

int main() {
    // 1. Load the custom provider by its name defined in its implementation
    // This assumes the provider is in the OpenSSL provider path 
    // or loaded as a module.
    OSSL_PROVIDER *hw_provider = OSSL_PROVIDER_load(NULL, "my_hardware_provider");

    if (hw_provider == NULL) {
        ERR_print_errors_fp(stderr);
        return 1;
    }

    // 2. Perform cryptographic operations (e.g., EVP_CipherInit_ex)
    // OpenSSL will now look for the implementation in your provider.

    // 3. Cleanup
    OSSL_PROVIDER_unload(hw_provider);
    return 0;
}
```

**Note for Implementation:** To implement the provider itself, you must define an `OSSL_DISPATCH` table containing the `OSSL_FUNC_PROVIDER_new` and `OSSL_FUNC_PROVIDER_functions` function pointers.

